INSERT INTO `reviews` VALUES (1,4,1,5,'Tour Đà Lạt lần nào đi cũng thấy yêu, không khí trong lành, dịch vụ tour chuyên nghiệp.','2026-04-23 01:00:29',1),(2,5,2,4,'Tour Đà Nẵng – Hội An khá tốt, đặc biệt ấn tượng với Bà Nà Hills và Cầu Vàng. Dịch vụ ổn, sẽ quay lại.','2026-04-23 01:00:29',2),(3,6,3,5,'Hạ Long quá đẹp, du thuyền sang trọng, đồ ăn ngon. Đây là chuyến đi đáng nhớ nhất của tôi.','2026-04-23 01:00:29',3),(4,7,5,5,'Phú Quốc rất đẹp, biển trong xanh, dịch vụ resort tốt. Trải nghiệm cáp treo Hòn Thơm rất ấn tượng.','2026-05-10 08:00:00',4),(5,8,6,4,'Sapa mát mẻ, cảnh đẹp, Fansipan rất hùng vĩ. Tuy nhiên thời tiết hơi lạnh nhưng vẫn rất đáng trải nghiệm.','2026-05-15 08:00:00',5),(6,4,9,5,'Tour Côn Đảo rất thanh bình, phù hợp để đi tìm sự tĩnh lặng và ngắm biển hoang sơ.','2026-05-20 08:00:00',6),(7,5,10,4,'Mộc Châu mùa hoa mận tuyệt vời, thác Dải Yếm rất đẹp. Điểm trừ là đồ ăn hơi cay so với mình.','2026-05-25 08:00:00',7),(8,6,11,5,'Biển Kỳ Co rất trong xanh, hướng dẫn viên nhiệt tình, hải sản Quy Nhơn ngon bá cháy!','2026-06-05 08:00:00',8),(10,8,16,5,'Chuyến thám hiểm Sơn Đoòng thực sự là một trải nghiệm thay đổi cuộc đời tôi. Quá vĩ đại!','2026-07-10 08:00:00',10),(11,7,4,4,'Biển Nha Trang trong xanh, các trò chơi tại VinWonders rất vui và đa dạng.','2026-04-23 01:00:29',14),(12,8,9,5,'Côn Đảo mang vẻ đẹp hoang sơ và linh thiêng, một chuyến đi rất ý nghĩa cho tâm hồn.','2026-04-23 01:00:29',15),(13,4,17,4,'Vũng Tàu gần nên đi cuối tuần rất tiện, đồ ăn ngon và giá cả hợp lý.','2026-04-23 01:00:29',16),(14,5,1,5,'Đà Lạt vẫn giữ được nét thơ mộng vốn có, lịch trình tour được sắp xếp khoa học.','2026-06-20 08:00:00',17),(15,6,2,5,'Hội An lung linh về đêm, tôi rất thích không khí cổ kính và bình lặng ở đây.','2026-07-15 08:00:00',18),(16,7,9,5,'Dịch vụ ở Côn Đảo ngày càng tốt hơn, hướng dẫn viên kể chuyện lịch sử rất cảm động.','2026-07-28 08:00:00',19),(17,5,4,5,'Check-in Nha Trang mùa này biển đẹp tuyệt, tour đi các đảo lặn ngắm san hô rất vui.','2026-04-23 01:00:29',22),(18,6,7,5,'Cố đô Huế mang vẻ đẹp trầm mặc, các di tích lăng tẩm được bảo tồn rất tốt.','2026-04-23 01:00:29',23),(19,7,11,4,'Quy Nhơn nắng gió nhưng biển Kỳ Co thì không chê vào đâu được, nước trong vắt.','2026-04-23 01:00:29',24),(20,8,15,5,'Đảo Bình Ba yên bình, trải nghiệm ăn tôm hùm nướng ngay trên bè thực sự rất ngon.','2026-04-23 01:00:29',25),(21,4,5,5,'Phú Quốc mùa này nắng vàng biển xanh, rất phù hợp cho một kỳ nghỉ dưỡng thực thụ.','2026-05-26 08:00:00',26),(22,5,6,5,'Chinh phục đỉnh Fansipan là trải nghiệm không thể quên, cảm giác đứng giữa mây trời rất tuyệt.','2026-05-01 08:00:00',27),(23,7,13,4,'Chợ nổi Cái Răng tấp nập, trải nghiệm sông nước miền Tây thật thú vị và dân dã.','2026-09-10 08:00:00',29),(24,8,17,5,'Tượng Chúa Kitô view từ trên cao ngắm toàn cảnh Vũng Tàu đẹp mê hồn, đáng để leo bậc thang.','2026-04-23 01:00:29',30),(25,5,3,4,'Phong cảnh Vịnh Hạ Long mờ ảo trong sương rất đẹp, đồ ăn trên tàu đa dạng.','2026-04-23 01:00:29',32),(26,6,18,5,'Biển Hồ Pleiku xanh mướt, không khí cao nguyên buổi sớm thật dễ chịu và sảng khoái.','2026-04-23 01:00:29',33),(27,7,2,5,'Đà Nẵng sạch sẽ, văn minh, tour đi Bà Nà được sắp xếp rất đúng giờ và không phải chờ đợi lâu.','2026-04-23 01:00:29',34),(28,8,7,4,'Thưởng thức ca Huế trên sông Hương là một trải nghiệm văn hóa rất đặc sắc.','2026-06-15 08:00:00',35),(29,4,12,5,'Cáp treo lên đỉnh Núi Bà Đen nhanh và hiện đại, dịch vụ tại khu du lịch rất tốt.','2026-08-18 08:00:00',36),(30,5,15,5,'Bãi biển Bình Ba hoang sơ, hải sản tươi sống giá cả phải chăng, rất hài lòng với chuyến đi.','2026-10-15 08:00:00',37),(31,8,3,5,'Tour tổ chức chuyên nghiệp, xe đưa đón đời mới đi rất êm, HDV cực kỳ vui tính.','2026-04-23 01:00:29',40),(32,4,18,5,'Dịch vụ tour rất hài lòng','2026-11-25 08:00:00',91),(33,4,8,3,'Tour đi bình thường , delay chuyến bay ','2026-05-05 22:31:28',81),(34,4,3,5,'1234','2026-05-05 22:35:45',71);
/*!40000 ALTER TABLE `reviews` ENABLE KEYS */;
