INSERT INTO `services` VALUES (1,'Ăn sáng','an-sang','Bao gồm bữa sáng buffet tại khách sạn với đa dạng món ăn Á - Âu, đảm bảo dinh dưỡng và phù hợp khẩu vị nhiều đối tượng khách hàng.',1,'2026-04-23 01:00:29','2026-04-23 01:00:29'),(2,'Xe đưa đón','xe-dua-don','Xe du lịch đời mới, máy lạnh, đưa đón khách theo lịch trình, đảm bảo an toàn, đúng giờ và tiện nghi suốt hành trình.',1,'2026-04-23 01:00:29','2026-04-23 01:00:29'),(3,'Hướng dẫn viên','huong-dan-vien','Hướng dẫn viên chuyên nghiệp, am hiểu tuyến điểm, nhiệt tình hỗ trợ và cung cấp thông tin chi tiết trong suốt chuyến đi.',1,'2026-04-23 01:00:29','2026-04-23 01:00:29'),(4,'Vé tham quan','ve-tham-quan','Bao gồm toàn bộ vé tham quan các điểm trong chương trình, không phát sinh chi phí ngoài lịch trình đã công bố.',1,'2026-04-23 01:00:29','2026-04-23 01:00:29'),(5,'Bảo hiểm du lịch','bao-hiem','Bảo hiểm du lịch trọn gói, đảm bảo quyền lợi cho khách trong suốt thời gian tham gia tour.',1,'2026-04-23 01:00:29','2026-04-23 01:00:29');
/*!40000 ALTER TABLE `services` ENABLE KEYS */;
UNLOCK TABLES;

