-- Dumping data for table `tour_itineraries`
--

LOCK TABLES `tour_itineraries` WRITE;
/*!40000 ALTER TABLE `tour_itineraries` DISABLE KEYS */;
INSERT INTO `tour_itineraries` VALUES (1,1,1,'CHÀO MỪNG ĐÀ LẠT – ĐÓN KHÁCH THAM QUAN\n08:00: Xe và hướng dẫn viên đón quý khách tại sân bay/bến xe Đà Lạt, đưa về khách sạn làm thủ tục nhận phòng. Nghỉ ngơi.\n14:00: Tham quan Hồ Xuân Hương – biểu tượng của thành phố, tiếp tục check-in tại Quảng trường Lâm Viên với công trình kiến trúc độc đáo.\n16:00: Tham quan Thung lũng Tình Yêu và Vườn hoa Thành phố với hàng trăm loài hoa đặc trưng của Đà Lạt.\n18:30: Dùng bữa tối tại nhà hàng. Sau đó tự do khám phá chợ đêm Đà Lạt, thưởng thức đặc sản địa phương.'),(2,1,2,'ĐÀ LẠT – ĐỒI CHÈ – THÁC DATANLA (Ăn sáng, trưa)\n05:30: Khởi hành đi Đồi chè Cầu Đất, săn mây và đón bình minh.\n08:00: Dùng bữa sáng. Trở về trung tâm thành phố.\n10:00: Tham quan Thác Datanla, trải nghiệm máng trượt xuyên rừng hiện đại.\n14:00: Tham quan Chùa Linh Phước (Chùa Ve Chai) với kiến trúc khảm sành độc đáo.\nTối: Tự do nghỉ ngơi hoặc khám phá thành phố về đêm.'),(3,1,3,'TẠM BIỆT ĐÀ LẠT – TIỄN KHÁCH\n07:00: Dùng bữa sáng tại khách sạn.\n08:30: Tham quan Chợ Đà Lạt, mua sắm đặc sản.\n10:30: Làm thủ tục trả phòng, xe đưa quý khách ra sân bay/bến xe. Kết thúc chương trình.'),(4,2,1,'CHÀO MỪNG ĐÀ NẴNG – CITY TOUR\n08:00: Xe đón quý khách tại sân bay Đà Nẵng, đưa về khách sạn nhận phòng nghỉ ngơi.\n15:00: Tham quan Cầu Rồng, Cầu Tình Yêu, chụp hình check-in tại các điểm nổi bật của thành phố.\n16:30: Tắm biển Mỹ Khê – một trong những bãi biển đẹp nhất hành tinh.\n18:30: Dùng bữa tối tại nhà hàng. Sau đó tự do khám phá Đà Nẵng về đêm, dạo phố hoặc thưởng thức ẩm thực địa phương.'),(5,2,2,'BÀ NÀ HILLS – CẦU VÀNG\n07:30: Dùng bữa sáng tại khách sạn, khởi hành đi Bà Nà Hills.\n09:00: Trải nghiệm hệ thống cáp treo đạt kỷ lục thế giới, tham quan Cầu Vàng nổi tiếng.\n10:30: Tham quan vườn hoa Le Jardin, hầm rượu Debay và Làng Pháp.\n12:00: Dùng bữa trưa buffet tại nhà hàng trên đỉnh Bà Nà.\n14:00: Tham gia các trò chơi tại Fantasy Park.\n16:30: Xuống cáp treo, trở về khách sạn nghỉ ngơi.\n19:00: Tự do khám phá thành phố.'),(6,2,3,'TẠM BIỆT ĐÀ NẴNG – TIỄN KHÁCH\n07:30: Dùng bữa sáng, làm thủ tục trả phòng.\n08:30: Di chuyển đến phố cổ Hội An.\n09:30: Tham quan Chùa Cầu, nhà cổ Tấn Ký, hội quán Phúc Kiến.\n11:30: Tự do mua sắm và thưởng thức ẩm thực.\n13:30: Xe đưa quý khách ra sân bay. Kết thúc chương trình.'),(7,3,1,'HÀ NỘI – HẠ LONG (Ăn trưa, tối)\n07:30: Xe đón quý khách tại Hà Nội, khởi hành đi Hạ Long.\n11:30: Đến cảng, làm thủ tục lên du thuyền, nhận phòng.\n12:30: Dùng bữa trưa trên tàu với các món hải sản đặc trưng.\n14:00: Tham quan Hang Sửng Sốt – hang động đẹp nhất vịnh Hạ Long.\n15:30: Chèo kayak hoặc tham quan Hang Luồn.\n16:30: Tắm biển và leo núi tại đảo Titop.\n19:00: Dùng bữa tối trên tàu, tham gia câu mực đêm.'),(8,3,2,'HẠ LONG – HÀ NỘI (Ăn sáng, trưa)\n06:00: Ngắm bình minh, tập thể dục trên boong tàu.\n07:00: Dùng bữa sáng nhẹ.\n08:30: Tham quan thêm các điểm trên vịnh.\n09:30: Trả phòng.\n11:00: Dùng bữa trưa.\n12:00: Quay về Hà Nội. Kết thúc tour.'),(9,4,1,'CHÀO MỪNG NHA TRANG – ĐÓN KHÁCH\n09:00: Đón quý khách tại sân bay Cam Ranh, đưa về khách sạn nhận phòng.\n15:00: Tự do tắm biển, tham quan quảng trường Nha Trang.\n19:00: Dùng bữa tối, tự do khám phá chợ đêm.'),(10,4,2,'VINWONDERS (Ăn sáng, trưa)\n07:30: Dùng bữa sáng, khởi hành đi VinWonders.\n09:00: Trải nghiệm cáp treo vượt biển.\n10:00: Vui chơi tại công viên nước và khu trò chơi.\n12:00: Ăn trưa.\n14:00: Tiếp tục khám phá khu vui chơi.\n17:00: Trở về khách sạn.'),(11,4,3,'TOUR ĐẢO (Ăn sáng, trưa)\n08:00: Khởi hành tham quan các đảo.\n10:00: Lặn biển ngắm san hô.\n12:00: Ăn trưa hải sản.\n15:00: Trở về khách sạn nghỉ ngơi.'),(12,4,4,'TIỄN KHÁCH (Ăn sáng)\n07:00: Dùng bữa sáng.\n09:00: Trả phòng, tiễn sân bay.'),(13,5,1,'ĐÓN KHÁCH – KHÁM PHÁ PHÚ QUỐC (Ăn tối)\n09:00: Xe và hướng dẫn viên đón quý khách tại sân bay Phú Quốc, đưa về khách sạn/resort làm thủ tục nhận phòng. Nghỉ ngơi, thư giãn sau chuyến bay.\n15:00: Tự do tắm biển tại bãi biển riêng của resort, tận hưởng không gian trong lành và cảnh biển tuyệt đẹp của đảo ngọc.\n16:30: Tham quan Dinh Cậu – địa điểm tâm linh nổi tiếng, ngắm hoàng hôn trên biển.\n18:30: Dùng bữa tối tại nhà hàng với các món hải sản tươi sống.\n20:00: Tự do khám phá chợ đêm Phú Quốc, thưởng thức đặc sản như hải sản nướng, kem cuộn, nước mắm Phú Quốc.'),(14,5,2,'CÁP TREO HÒN THƠM – VUI CHƠI BIỂN (Ăn sáng, trưa)\n07:00: Dùng bữa sáng tại khách sạn.\n08:00: Xe đưa quý khách đến ga cáp treo An Thới.\n08:30: Trải nghiệm tuyến cáp treo vượt biển dài nhất thế giới đến Hòn Thơm, ngắm toàn cảnh quần đảo An Thới từ trên cao.\n09:30: Tự do tắm biển, vui chơi tại công viên nước Aquatopia Water Park với nhiều trò chơi hấp dẫn.\n12:00: Dùng bữa trưa buffet tại nhà hàng trên đảo.\n14:00: Tiếp tục tham gia các hoạt động giải trí, nghỉ ngơi.\n16:00: Quay trở lại đất liền bằng cáp treo.\n19:00: Tự do ăn tối và khám phá Phú Quốc về đêm.'),(15,5,3,'KHÁM PHÁ NAM ĐẢO – LẶN BIỂN (Ăn sáng, trưa)\n07:30: Dùng bữa sáng tại khách sạn.\n08:30: Khởi hành tham quan Nam Đảo.\n09:30: Tham quan cơ sở nuôi cấy ngọc trai, tìm hiểu quy trình sản xuất.\n10:30: Di chuyển ra đảo, tham gia lặn biển ngắm san hô, trải nghiệm câu cá.\n12:30: Dùng bữa trưa trên tàu hoặc tại nhà hàng với hải sản tươi sống.\n14:30: Tham quan nhà thùng nước mắm Phú Quốc, tìm hiểu nghề truyền thống lâu đời.\n16:00: Trở về khách sạn nghỉ ngơi.\n18:30: Tự do ăn tối, khám phá chợ đêm hoặc dạo biển.'),(16,5,4,'PHÚ QUỐC – TIỄN KHÁCH (Ăn sáng)\n07:00: Dùng bữa sáng tại khách sạn.\n08:00: Tự do nghỉ dưỡng, tắm biển hoặc mua sắm đặc sản.\n10:00: Làm thủ tục trả phòng.\n10:30: Xe đưa quý khách ra sân bay Phú Quốc, kết thúc chương trình.'),(17,6,1,'HÀ NỘI – SAPA – BẢN CÁT CÁT (Ăn trưa, tối)\n06:30: Xe và hướng dẫn viên đón quý khách tại điểm hẹn ở Hà Nội, khởi hành đi Sapa theo đường cao tốc Nội Bài – Lào Cai.\n09:30: Dừng chân nghỉ ngơi tại trạm dừng, thư giãn và dùng nhẹ.\n12:30: Đến Sapa, dùng bữa trưa tại nhà hàng địa phương với các món đặc sản vùng núi.\n14:00: Nhận phòng khách sạn, nghỉ ngơi.\n15:30: Khởi hành tham quan bản Cát Cát – nơi sinh sống của người H’Mông, tìm hiểu đời sống văn hóa, phong tục tập quán.\n17:30: Trở về khách sạn nghỉ ngơi.\n18:30: Dùng bữa tối tại nhà hàng.\n19:00: Tự do khám phá thị trấn Sapa, tham quan nhà thờ đá, thưởng thức các món nướng đặc trưng vùng cao.'),(18,6,2,'CHINH PHỤC FANSIPAN (Ăn sáng, trưa)\n07:00: Dùng bữa sáng tại khách sạn.\n08:00: Khởi hành đến ga cáp treo Fansipan.\n08:30: Trải nghiệm tuyến cáp treo đạt kỷ lục thế giới, chinh phục đỉnh Fansipan – “Nóc nhà Đông Dương”.\n10:30: Tham quan quần thể tâm linh trên đỉnh núi, chụp hình lưu niệm.\n12:00: Trở xuống và dùng bữa trưa tại nhà hàng.\n14:00: Tự do nghỉ ngơi hoặc khám phá Sapa như chợ Sapa, quảng trường trung tâm.\n18:30: Dùng bữa tối tự túc, thưởng thức đặc sản địa phương.\n19:00: Nghỉ đêm tại Sapa.'),(19,6,3,'SAPA – HÀ NỘI (Ăn sáng)\n07:00: Dùng bữa sáng tại khách sạn.\n08:00: Tự do tham quan chợ Sapa, mua sắm đặc sản địa phương như thổ cẩm, nông sản.\n10:00: Làm thủ tục trả phòng.\n10:30: Khởi hành về Hà Nội.\n13:30: Dừng chân nghỉ ngơi, ăn trưa tự túc trên đường.\n16:30: Về đến Hà Nội, kết thúc chương trình.'),(20,7,1,'ĐÓN KHÁCH – THAM QUAN CỐ ĐÔ HUẾ (Ăn trưa, tối)\nSáng: Xe đón quý khách tại sân bay/ga Huế, đưa về trung tâm thành phố.\n11:30: Dùng bữa trưa tại nhà hàng với các món đặc sản Huế.\n13:30: Nhận phòng khách sạn nghỉ ngơi.\n15:00: Tham quan Đại Nội Huế – Hoàng thành triều Nguyễn, tìm hiểu lịch sử và kiến trúc cung đình.\n17:30: Trở về khách sạn nghỉ ngơi.\n18:30: Dùng bữa tối.\nTối: Tự do dạo phố, thưởng thức ẩm thực Huế hoặc tham gia chương trình nghe ca Huế trên sông Hương.'),(21,7,2,'HUẾ – PHONG NHA (Ăn sáng, trưa)\n06:30: Dùng bữa sáng tại khách sạn.\n07:30: Khởi hành đi Phong Nha – Kẻ Bàng.\n11:30: Dùng bữa trưa tại nhà hàng địa phương.\n13:00: Tham quan động Phong Nha bằng thuyền, chiêm ngưỡng hệ thống hang động kỳ vĩ.\n16:30: Khởi hành về Huế.\n19:30: Về đến Huế, nghỉ ngơi, ăn tối tự túc.'),(22,7,3,'HUẾ – TIỄN KHÁCH (Ăn sáng)\n07:00: Dùng bữa sáng tại khách sạn.\n08:00: Tham quan Chùa Thiên Mụ – biểu tượng tâm linh của Huế.\n09:30: Tham quan chợ Đông Ba, mua đặc sản.\n11:00: Trả phòng khách sạn.\nXe đưa quý khách ra sân bay/ga Huế. Kết thúc chương trình.'),(23,8,1,'HÀ NỘI – TRÀNG AN (Ăn trưa)\n07:30: Xe đón quý khách tại Hà Nội, khởi hành đi Ninh Bình.\n09:30: Đến Ninh Bình, nghỉ ngơi.\n10:00: Tham quan khu du lịch Tràng An bằng thuyền, chiêm ngưỡng cảnh sắc non nước hữu tình.\n12:30: Dùng bữa trưa tại nhà hàng với các món đặc sản như dê núi, cơm cháy.\n14:00: Tham quan chùa Bái Đính – quần thể chùa lớn nhất Việt Nam.\n17:00: Nhận phòng khách sạn, nghỉ ngơi.\n18:30: Dùng bữa tối.\n20:00: Tự do nghỉ ngơi hoặc khám phá Ninh Bình về đêm.'),(24,8,2,'TAM CỐC – HÀ NỘI (Ăn sáng, trưa)\n07:00: Dùng bữa sáng tại khách sạn.\n08:00: Tham quan Tam Cốc – Bích Động bằng thuyền, khám phá hệ thống hang động tự nhiên.\n11:30: Trả phòng khách sạn.\n12:00: Dùng bữa trưa tại nhà hàng.\n13:30: Khởi hành về Hà Nội.\n16:00: Về đến Hà Nội, kết thúc chương trình.'),(25,9,1,'CHÀO MỪNG CÔN ĐẢO – TÌM HIỂU LỊCH SỬ\n08:00: Hướng dẫn viên đón quý khách tại sân bay Tân Sơn Nhất, làm thủ tục bay đi Côn Đảo.\n10:30: Đến sân bay Cỏ Ống (Côn Đảo), xe đưa đoàn về trung tâm thị trấn, nhận phòng khách sạn và nghỉ ngơi ngắm cảnh biển.\n12:00: Quý khách dùng bữa trưa tại nhà hàng địa phương với các món hải sản biển đảo.\n14:00: Xe và HDV đưa đoàn tham quan Cựu nhà tù Côn Đảo, tìm hiểu về Di tích lịch sử Quốc gia đặc biệt.\n16:30: Tự do tắm biển tại Bãi Đầm Trầu.\n18:30: Ăn tối tại nhà hàng.\n23:00: Đoàn tham gia chương trình viếng Nghĩa trang Hàng Dương, viếng mộ cô Sáu linh thiêng.'),(26,9,2,'KHÁM PHÁ HÒN BẢY CẠNH – LẶN NGẮM SAN HÔ\n07:00: Đoàn dùng điểm tâm sáng tại nhà hàng khách sạn.\n08:30: Lên cano khởi hành đi tham quan Hòn Bảy Cạnh, tham gia chương trình lặn ngắm san hô dưới đáy biển tuyệt đẹp.\n11:30: Thưởng thức bữa trưa BBQ hải sản dã ngoại ngay trên bãi biển.\n14:00: Quay về đảo lớn, tiếp tục tham quan Miếu bà Phi Yến, chùa Núi Một.\n16:00: Tự do tắm biển.\n18:30: Dùng bữa tối. Buổi tối quý khách tự do dạo biển Côn Đảo.'),(27,9,3,'TẠM BIỆT CÔN ĐẢO\n06:30: Dùng điểm tâm sáng sớm, dạo biển đón bình minh.\n08:00: Xe đưa đoàn đi chợ Côn Đảo tự do mua sắm đặc sản bàng, hải sản khô.\n10:30: Làm thủ tục trả phòng khách sạn.\n11:30: Ăn trưa nhẹ tại nhà hàng địa phương.\n13:00: Xe đưa đoàn ra sân bay Cỏ Ống làm thủ tục đáp chuyến bay về lại điểm khởi hành, kết thúc lịch trình.'),(28,10,1,'CHÀO MỪNG MỘC CHÂU – ĐỒI CHÈ TRÁI TIM\n06:00: Xe và HDV đón quý khách tại điểm hẹn ở Hà Nội, khởi hành đi Mộc Châu.\n09:00: Dừng chân ngắm cảnh và chụp hình tại Đèo Thung Khe.\n12:00: Đến Mộc Châu, ăn trưa tại nhà hàng với các món đặc sản Tây Bắc.\n14:00: Nhận phòng homestay và nghỉ ngơi.\n15:30: Khởi hành tham quan Đồi chè trái tim xanh mướt, tha hồ check-in sống ảo.\n18:30: Thưởng thức bữa tối đặc sản với bê chao và cá suối.\n20:00: Giao lưu lửa trại, ca múa nhạc dân tộc (nếu đi đoàn đông).'),(29,10,2,'THÁC DẢI YẾM – RỪNG THÔNG BẢN ÁNG\n07:00: Ăn sáng tại homestay với bánh cuốn hoặc phở.\n08:30: Xe đưa đoàn đến tham quan Thác Dải Yếm hùng vĩ và dạo bước trên cầu kính Tình Yêu.\n10:30: Khám phá Rừng thông Bản Áng, đạp xe quanh hồ.\n12:30: Trả phòng và ăn trưa tại nhà hàng.\n14:00: Mua sắm đặc sản sữa Mộc Châu, chè xanh, măng khô.\n15:00: Lên xe khởi hành về lại Hà Nội.\n18:00: Về đến thủ đô, chia tay quý khách.'),(30,11,1,'CHÀO MỪNG QUY NHƠN – THIÊN ĐƯỜNG KỲ CO\n08:00: Đón khách tại sân bay Phù Cát (Quy Nhơn), đưa đoàn về trung tâm.\n09:30: Tham quan Tháp Đôi, một trong những công trình kiến trúc Chăm cổ kính.\n11:30: Ăn trưa tại nhà hàng, sau đó nhận phòng khách sạn nghỉ ngơi.\n14:30: Khởi hành đi Kỳ Co, di chuyển bằng cano cao tốc ra đảo.\n15:00: Tắm biển Kỳ Co trong vắt, lặn ngắm san hô phong phú.\n17:00: Khám phá Eo Gió – nơi đón hoàng hôn đẹp nhất Việt Nam.\n19:00: Thưởng thức hải sản Quy Nhơn tươi sống tại nhà hàng ven biển.'),(31,11,2,'KHÁM PHÁ PHÚ YÊN – TÔI THẤY HOA VÀNG TRÊN CỎ XANH\n07:30: Dùng buffet sáng.\n08:30: Khởi hành đi Phú Yên. Dọc đường ngắm cung đường biển tuyệt đẹp.\n10:00: Tham quan Nhà thờ Mằng Lăng cổ kính với kiến trúc Gothic.\n11:30: Thưởng thức hải sản Đầm Ô Loan trứ danh.\n14:00: Khám phá Ghềnh Đá Đĩa - kiệt tác thiên nhiên với các khối đá hình lục giác độc đáo.\n16:00: Check-in Bãi Xép – phim trường \"Tôi thấy hoa vàng trên cỏ xanh\".\n18:30: Trở về Quy Nhơn dùng bữa tối.'),(32,11,3,'TẠM BIỆT QUY NHƠN\n07:00: Ăn sáng tại khách sạn.\n08:30: Tự do dạo biển ngắm bình minh, tắm biển.\n10:00: Xe đưa đoàn đi chợ mua sắm đặc sản Quy Nhơn như bánh ít lá gai, nem chả.\n11:30: Trả phòng khách sạn, dùng bữa cơm trưa nhẹ nhàng.\n13:30: Xe đưa đoàn ra sân bay Phù Cát. Kết thúc hành trình đầy kỷ niệm.'),(33,12,1,'CHÀO MỪNG TÂY NINH – CHINH PHỤC NÚI BÀ ĐEN\n06:00: Khởi hành từ TP.HCM đi Tây Ninh.\n08:00: Thưởng thức đặc sản bánh canh Trảng Bàng.\n09:30: Đến Khu du lịch núi Bà Đen. Trải nghiệm tuyến cáp treo hiện đại lên đỉnh núi.\n10:30: Tham quan và viếng Chùa Bà, cầu bình an và tài lộc.\n11:30: Check-in đỉnh núi săn mây, chiêm ngưỡng toàn cảnh đồng bằng Tây Ninh xanh thẳm.\n12:30: Ăn trưa buffet tại nhà hàng Vân Sơn trên đỉnh núi.\n14:30: Di chuyển xuống núi, xe đưa đoàn đến Toà thánh Tây Ninh ngắm kiến trúc độc đáo.\n16:00: Mua sắm đặc sản muối tôm Tây Ninh.\n17:00: Khởi hành về lại TP.HCM, kết thúc chương trình.'),(34,13,1,'CHÀO MỪNG CẦN THƠ – KHÁM PHÁ NÉT ĐẸP MIỀN TÂY\n07:00: Đón quý khách tại điểm hẹn TP.HCM đi miền Tây.\n09:00: Dừng chân tham quan Mekong Rest Stop.\n11:00: Đến Cần Thơ. Viếng Thiền viện Trúc Lâm Phương Nam.\n12:30: Dùng bữa trưa tại Làng Du Lịch Mỹ Khánh, thưởng thức ẩm thực miệt vườn.\n14:00: Nhận phòng khách sạn.\n15:30: Tham quan Nhà cổ Bình Thủy, nơi quay cảnh trong phim \"Người Tình\".\n18:30: Dùng tiệc tối trên du thuyền Cần Thơ, lênh đênh sông nước nghe đờn ca tài tử.\n21:00: Tự do dạo bến Ninh Kiều về đêm.'),(35,13,2,'CHỢ NỔI CÁI RĂNG – TẠM BIỆT CẦN THƠ\n05:30: Thức dậy sớm, xuống thuyền đi tham quan Chợ nổi Cái Răng tấp nập giao thương trên sông.\n07:30: Trở về khách sạn dùng điểm tâm sáng.\n09:00: Tham quan lò hủ tiếu truyền thống, thử tài làm hủ tiếu pizza.\n11:30: Trả phòng khách sạn. Ăn trưa đặc sản.\n13:30: Lên xe khởi hành về lại TP.HCM, trên đường mua đặc sản trái cây miền Tây.\n17:00: Đến TP.HCM.'),(36,14,1,'CHÀO MỪNG HÀ GIANG – CỔNG TRỜI QUẢN BẠ\n06:00: Khởi hành từ Hà Nội theo hướng cao tốc Nội Bài - Lào Cai.\n12:00: Dùng bữa trưa tại thành phố Hà Giang.\n14:00: Tiếp tục hành trình, dừng chân chụp hình tại Cột mốc số 0 Hà Giang.\n16:00: Vượt dốc Bắc Sum, check in cổng trời Quản Bạ, ngắm núi đôi Cô Tiên.\n18:30: Nhận phòng khách sạn tại Yên Minh.\n19:00: Dùng bữa tối đặc sản rừng núi, tự do nghỉ ngơi.'),(37,14,2,'CAO NGUYÊN ĐÁ ĐỒNG VĂN – CỘT CỜ LŨNG CÚ\n07:00: Trả phòng, dùng điểm tâm sáng.\n08:30: Thăm dốc Thẩm Mã, làng văn hóa Lũng Cẩm trong phim \"Chuyện của Pao\".\n11:00: Di chuyển đến Dinh thự Vua Mèo Vương Chính Đức với kiến trúc độc lạ.\n12:30: Dùng bữa trưa tại nhà hàng.\n14:30: Lên xe đến Cột cờ Lũng Cú, điểm cực Bắc thiêng liêng của Tổ Quốc.\n17:00: Đến Đồng Văn, nhận phòng khách sạn nghỉ ngơi.\n19:00: Ăn tối, dạo phố cổ Đồng Văn, thưởng thức cafe phố cổ.'),(38,14,3,'ĐÈO MÃ PÍ LÈNG – SÔNG NHO QUẾ\n07:00: Dùng bữa sáng. Nếu đúng lịch sẽ đi chợ phiên Đồng Văn.\n08:30: Trả phòng, di chuyển đi đèo Mã Pí Lèng - tứ đại đỉnh đèo ngoạn mục.\n10:00: Trải nghiệm ngồi thuyền trên dòng sông Nho Quế, ngắm hẻm Tu Sản tráng lệ.\n12:30: Dùng bữa trưa tại thị trấn Mèo Vạc.\n14:00: Lên xe về lại thành phố Hà Giang qua những cung đường đèo quanh co.\n18:30: Về đến Hà Giang, nhận phòng và ăn tối. Nghỉ đêm tại Hà Giang.'),(39,14,4,'TẠM BIỆT HÀ GIANG\n07:00: Ăn sáng tại khách sạn, tự do mua mật ong rừng, thảo quả.\n10:00: Làm thủ tục trả phòng.\n11:30: Dùng cơm trưa tại nhà hàng.\n13:00: Khởi hành về lại Hà Nội.\n18:00: Đến Hà Nội, chia tay quý khách.'),(40,15,1,'CHÀO MỪNG BÌNH BA – ĐẢO TÔM HÙM\n07:00: Xe đón quý khách tại điểm hẹn ở Cam Ranh, di chuyển đến cảng.\n08:00: Lên cano cao tốc ra đảo Bình Ba (đảo Tôm hùm).\n09:00: Đến đảo, di chuyển bằng xe điện đi quanh đảo tham quan Bãi Nồm, Bãi Chướng.\n11:30: Dùng bữa trưa hải sản trên bè nổi.\n14:00: Nhận phòng nhà nghỉ trên đảo, nghỉ ngơi.\n15:30: Tham gia hoạt động tắm biển và lặn ngắm san hô tại Bãi Nhà Cũ với làn nước trong vắt.\n18:30: Dùng tiệc tối với đặc sản Tôm hùm nướng trứ danh và hải sản phong phú.\n20:30: Giao lưu karaoke hoặc tự do đi bộ dạo bờ biển cực chill đêm đảo vắng.'),(41,15,2,'NGẮM BÌNH MINH – TẠM BIỆT BÌNH BA\n05:30: Dậy sớm đi ngắm bình minh trên bãi biển hoang sơ, tận hưởng không khí trong lành.\n07:00: Thưởng thức bữa sáng với các món ăn đặc trưng của dân đảo như bún chả cá, bánh căn.\n08:30: Tự do đi chợ đảo Bình Ba tìm mua hải sản khô hoặc sống giá rẻ.\n10:00: Trả phòng, cano đưa đoàn trở lại cảng đất liền Cam Ranh.\n11:00: Lên xe đưa đoàn về sân bay hoăc trung tâm thành phố, khép lại chương trình khám phá tự nhiên tuyệt vời.'),(42,16,1,'CHÀO MỪNG PHONG NHA – BẮT ĐẦU HÀNH TRÌNH THÁM HIỂM\n06:00: Khởi hành từ Đồng Hới đi vườn quốc gia Phong Nha - Kẻ Bàng.\n08:00: Gặp gỡ các chuyên gia hang động, kiểm tra thể lực, trang thiết bị an toàn kỹ lưỡng.\n09:30: Bắt đầu hành trình đi bộ băng rừng, lội suối xuyên qua cánh rừng rậm rạp.\n12:30: Dừng nghỉ dùng bữa trưa dã ngoại giữa thiên nhiên.\n14:00: Tiếp tục leo qua núi đá gai góc trước khi đến bản Đoòng của người dân bản địa nghỉ ngơi ngắn.\n16:30: Tiếp cận cửa hang Én, lội qua dòng suối ngầm tiến vào trong hang rộng mênh mông.\n18:00: Đội khuân vác thiết lập bãi cắm trại hoàng tráng bên trong hang Én.\n19:30: Dùng bữa tối nướng BBQ, nghe những câu chuyện thám hiểm kỳ thú.'),(43,16,2,'CHINH PHỤC HANG SƠN ĐOÒNG VĨ ĐẠI\n07:00: Thức dậy trong ánh nắng rọi từ cửa hang khổng lồ, dùng điểm tâm.\n08:30: Bắt đầu đi sâu hơn để chính thức tiến vào cửa hang Sơn Đoòng nguyên sơ.\n10:00: Leo dốc đá trơn trượt có dây nạo bảo hiểm, băng qua các dòng sông ngầm chảy róc rách.\n12:30: Nghỉ chân trong hang tối dùng bữa trưa gọn nhẹ.\n14:00: Chiêm ngưỡng những cột thạch nhũ nghìn năm tinh xảo vĩ đại như những toà tháp chọc trời.\n16:30: Dựng lều trại tại hố sụt số 1, nơi có những tia nắng chiếu xuống tận đáy động.\n18:30: Dùng bữa tối do thợ nấu địa phương chuẩn bị. Ngủ qua đêm trong lều bạt.'),(44,16,3,'KHÁM PHÁ THẢM THỰC VẬT ĐỘC ĐÁO\n07:00: Ăn sáng tiếp tục hành trình băng qua Doline 2, ngắm thảm thực vật mọc rợp trời xanh ngay trong lòng hang.\n09:00: Trải nghiệm đu dây (rapelling) và vượt sông ngầm với bè nổi thú vị.\n12:00: Ăn trưa tại vòm hang siêu vĩ đại được mệnh danh là Hang Sáng rực rỡ.\n14:30: Dò tìm hành lang thạch nhũ Bức tường Việt Nam cao ngất.\n17:00: Đến hố sụt số 2, cắm trại đêm cuối.\n19:00: Liên hoan chia tay hành trình thám hiểm tại đại bản doanh.'),(45,16,4,'HOÀN THÀNH CHUYẾN THÁM HIỂM LỊCH SỬ\n07:30: Thức dậy, thu dọn toàn bộ vật dụng không để lại rác trong hang động.\n09:00: Leo khỏi Bức tường Việt Nam để thoát hang, trở ra không gian bên ngoài.\n12:00: Băng xuyên rừng nhiệt đới theo lối mòn về con đường mòn Hồ Chí Minh.\n14:30: Xe máy kéo hoặc xe off-road đón đoàn trở lại đường lớn.\n16:00: Lên xe đưa về khu resort nghỉ dưỡng tắm rửa, tận hưởng tự do thư giãn phục hồi.\n18:00: Khép lại chuyến đi lịch sử thay đổi cuộc đời.'),(46,17,1,'CHÀO MỪNG VŨNG TÀU – CHINH PHỤC TƯỢNG CHÚA KITÔ\n07:00: Khởi hành từ TP.HCM bằng đường cao tốc Long Thành - Dầu Giây di chuyển êm ái.\n09:30: Đến Vũng Tàu. Tham quan đồi Cừu Suối Nghệ để chụp hình với những chú cừu dễ thương.\n11:30: Dùng bữa trưa tại nhà hàng trung tâm thành phố.\n13:30: Nhận phòng khách sạn, tự do nghỉ ngơi lấy sức.\n15:00: Đưa đoàn chinh phục hơn 800 bậc thang lên Tượng Chúa Kitô Vua trên núi Nhỏ, nhắm cảnh toàn TP.\n16:30: Tự do tắm biển tại Bãi Sau - Thuỳ Vân trong làn sóng hiền hoà mát rượi.\n18:30: Thưởng thức bữa tối tại chợ Quê hải sản tươi ngon, dạo biển đêm nhâm nhi cafe.'),(47,17,2,'TẠM BIỆT VŨNG TÀU – TRỞ VỀ TP.HCM\n07:00: Thưởng thức bữa sáng sớm tại khách sạn.\n08:30: Xe đưa khách đến Mũi Nghinh Phong chụp ảnh cổng trời, thăm Hải đăng cổ hướng biển.\n10:30: Mua sắm đặc sản mắm Trí Hải, cá thu tươi, hải sản một nắng dồi dào về làm quà.\n11:30: Về lại khách sạn làm thủ tục trả phòng.\n12:30: Dùng điểm tâm trưa và ghé dùng thử sữa bò Long Thành.\n14:30: Xe xuất phát đưa đoàn trở về TP.HCM.\n17:00: Đưa đón tại điểm hẹn trung tâm.'),(48,18,1,'CHÀO MỪNG PLEIKU – BIỂN HỒ T’NƯNG\n08:00: Đón tại sân bay Pleiku xinh đẹp đầy sương sớm.\n09:30: Khởi hành tham quan Biển Hồ T’Nưng, đôi mắt ngọc lung linh của Tây Nguyên.\n11:30: Dùng bữa trưa với món phở khô Gia Lai trứ danh nổi tiếng hai tô.\n13:30: Về khách sạn điểm trung tâm nhận phòng, thả dốc tĩnh tâm.\n15:00: Khám phá nhà máy thuỷ điện Yaly kì vĩ mang nhịp đập kinh tế của vùng rừng núi.\n17:30: Quanh quẩn quảng trường Đại Đoàn Kết, chiêm ngưỡng tượng đài Bác Hồ đồ sộ.\n19:00: Quý khách tự do ăn tối, trải nghiệm ẩm thực đường phố, gà nướng cơm lam.'),(49,18,2,'LÀNG VĂN HÓA TÂY NGUYÊN – NÚI LỬA CHƯ ĐĂNG YA\n07:00: Ăn sáng hương vị mộc mạc đặc sắc.\n08:30: Hành trình di chuyển đến ngọn đồi chè Biển hồ bạt ngàn thẳng tắp một hàng dọc lãng mạn.\n10:00: Dạo qua Hàng thông trăm tuổi đẹp như tranh vẽ Châu Âu giữa lòng phố núi.\n11:30: Dùng tiệc trưa đặc thù vùng miền.\n13:30: Thăm Núi lửa Chư Đăng Ya mang hình phễu kỳ quan hiếm có, tuỳ thời điểm ngắm dã quỳ hoa nhuộm vàng rực núi đồi.\n15:30: Di chuyển vào sâu trong buôn làng đồng bào dân tộc thiểu số, tìm hiểu thói quen tập tục lâu đời.\n18:00: Giao lưu cồng chiêng, tận hưởng tiệc thịt nướng ngay bên bếp lửa bập bùng truyền thống.'),(50,18,3,'TẠM BIỆT PHỐ NÚI GIA LAI\n07:30: Ngắm sương lãng đãng dạo bộ công viên, làm tô bún bò bữa sớm.\n09:00: Tự do đi tham quan mua sắm đặc sản tiêu, cafe, mắc ca ngay tại chợ nội ô.\n11:00: Thu xếp hành lí, trả phòng.\n11:30: Xe trung chuyển chở quý đoàn thưởng thức món gà xé phay thanh nhẹ cho bữa trưa.\n13:00: Đưa khách ra khu vực sân bay khởi hành về nơi bắt đầu, kết thúc tốt đẹp đầy cung bậc.');
/*!40000 ALTER TABLE `tour_itineraries` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `tour_services`
--

DROP TABLE IF EXISTS `tour_services`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tour_services` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tour_id` int NOT NULL,
  `service_id` int NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_tour_service` (`tour_id`,`service_id`),
  KEY `service_id` (`service_id`),
  CONSTRAINT `tour_services_ibfk_1` FOREIGN KEY (`tour_id`) REFERENCES `tours` (`id`) ON DELETE CASCADE,
  CONSTRAINT `tour_services_ibfk_2` FOREIGN KEY (`service_id`) REFERENCES `services` (`id`) ON DELETE CASCADE
